"""
MKT Original Commentary — 1 Samuel chapters 28–31
Run: python3 scripts/zc-original-1samuel-28-31.py

Source data used:
- data/interlinear/1samuel.json
- data/translation/glossary-hebrew.json (ʾôḇ, ʾĕlōhîm, ḥāzaq, bāśar)
- data/translation/notes/1samuel.json (tokens for key verses)
- data/translation/draft/mediating/1samuel.json (MKT text)

Key decisions in this range:
- ʾôḇ (H178): rendered "medium/spirit" — denotes the hollow pit through which spirits were
  summoned, then by extension the practitioner; not simply "ghost"
- ʾĕlōhîm (H430) in 28:13: rendered "divine figure" in MKT — the ambiguity is real; the
  word is grammatically plural but the description is singular ("an old man in a robe"); whether
  this was the actual spirit of Samuel or a demonic apparition is left deliberately open by the text
- rāgaz (H7264) in 28:15: "disturbed" — to be agitated, to quake; carries emotional disturbance,
  not just physical awakening
- ṣar (H6145) in 28:16: "adversary" — same root as śāṭān; YHWH has become what Saul feared from
  the Philistines; the covenant rupture is complete
- ḥāzaq (H2388) Hithpael in 30:6: "strengthened himself" — the reflexive form means self-directed
  strengthening; David draws strength into himself from YHWH rather than receiving it passively
- infinitive absolute constructions in 30:8: nāśōg tāśîg / haṣṣēl taṣṣîl — double certainty idiom
- bāśar (H1319) in 31:9: "announce the victory" — the gospel root; the Philistines' announcement
  of Saul's death to their idols is a dark irony given the term's later theological freight
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

SAMUEL1 = {
  "28": {
    "1": '<p>Introductory temporal clause (<em>wayhî bāyyāmîm hāhēm</em>, "in those days") links this episode to the Philistine mobilization context. Achish\'s command to David — <em>yādōaʿ tēdaʿ</em> (literally "knowing you will know," infinitive absolute + imperfect = emphatic certainty) — underscores that this is not an invitation but a binding military commitment. The irony that David is now obligated to fight against Israel will drive chs 28–29.</p>',
    "2": '<p><em>ʾattāh tēdaʿ ʾēt ʾăšer yaʿăśeh ʿabdəḵā</em> — "you will see what your servant can do." David\'s reply is deliberately ambiguous — it commits to nothing specific. Achish interprets it as complete loyalty and names him permanent bodyguard (<em>šōmēr lərōʾšî</em>, keeper of my head). David never fights the battle; the Providence that resolves his dilemma comes from the Philistine commanders in ch29.</p>',
    "3": '<p><strong>ʾôḇ</strong> (H178) and <strong>yiddəʿōnî</strong> (H3049) — "mediums and necromancers." <em>ʾÔḇ</em> (singular and collective) denotes the hollow pit or wineskin through which spirits were thought to speak, and by extension the practitioner. <em>Yiddəʿōnî</em> derives from <em>yādaʿ</em> (to know) — the "knowing one," a spirit-familiar. Both are banned by the Mosaic code (Lev 19:31; 20:6, 27; Deut 18:11). Saul himself expelled (<em>hiʿbîr</em>, caused to pass/removed) them — and will now secretly seek one. The narrative plants the irony: the law Saul enforced against others he will break himself.</p>',
    "4": '<p>Geographical orientation: Shunem (Philistines, north side of Jezreel Valley) vs. Gilboa (Israelites, south side). The valley between them becomes the killing ground of ch31. The same Gilboa site will prompt David\'s lament in 2 Sam 1:21 ("mountains of Gilboa, let there be no dew or rain on you").</p>',
    "5": '<p><em>wayyarʾ šāʾûl ʾet maḥănēh pəlištîm wayyirāʾ wayyeḥerad libbô məʾōd</em> — "he was terrified; his heart shook with dread." Three fear-words: <em>yārēʾ</em> (to be afraid), <em>ḥārad</em> (to tremble/shudder), and <em>məʾōd</em> (greatly). The phrase <em>wayyeḥerad libbô</em> (his heart shook) uses <em>lēḇ</em> again as the seat of inner response. Saul\'s fear is extreme and total — the contrast with David, who "strengthened himself in YHWH" (30:6) after an equally devastating situation, could not be sharper.</p>',
    "6": '<p><strong>Three channels of revelation — all closed.</strong> <em>Wayyišʾal šāʾûl baYHWH wəlōʾ ʿānāhû</em> — "Saul inquired of the LORD, but the LORD did not answer him." The three failed channels: (1) <em>baḥălōmôt</em> — dreams; (2) <em>baûrîm</em> — the Urim (part of the priestly ephod, the sacred lot); (3) <em>bannəḇîʾîm</em> — prophets. This triad exhausts the legitimate means of divine revelation (cf. Num 12:6-8). The contrast with 30:7-8 — where David inquires through the ephod and immediately receives a clear answer — marks the theological divide: YHWH answers the king he has chosen and is silent to the king he has rejected.</p>',
    "7": '<p><em>baʿălat ʾôḇ</em> — "a woman who is a medium" (literally "mistress of a spirit-pit"). The feminine participle <em>baʿălat</em> (owner/possessor, from <em>baʿal</em>) used for the woman marks her as the authorized practitioner of her craft. Endor is in Manassite territory north of Jezreel — Saul must pass through or near Philistine-controlled terrain to reach her, adding physical danger to moral compromise.</p>',
    "8": '<p><em>wayyiṯḥappeś šāʾûl</em> — "Saul disguised himself" (Hithpael of <em>ḥāpas</em>, H2664, to search out / conceal oneself). The Hithpael reflexive indicates active self-concealment. The disguise is both literal (changed clothes, night travel) and symbolic: Saul who presented himself in his full royal height is now hidden. <em>Bāʾ baʿădê hallaylāh</em> — "came in the cover of night" — darkness accompanies the illicit act.</p>',
    "9": '<p>The woman invokes Saul\'s own policy against her: <em>ʾattāh yādaʿtā ʾēt ʾăšer ʿāśāh šāʾûl</em> — "you know what Saul has done." She uses the familiar "Saul" as if speaking to an outsider, not knowing she is addressing Saul himself. The dramatic irony peaks here: Saul hears his own name and his own enforcement of the ban described to his face.</p>',
    "10": '<p><em>wayyiššāḇaʿ lāh šāʾûl baYHWH lēʾmōr</em> — "Saul swore to her by the LORD." The formula <em>ḥay YHWH</em> (as the LORD lives) is the standard covenant oath. Saul invokes YHWH to protect a woman engaged in a practice YHWH forbids — the theological incoherence is complete. The oath itself is a further breach of the covenant he is already violating.</p>',
    "11": '<p>The woman asks <em>mî ʾaʿăleh lāḵ</em> — "who shall I bring up for you?" (<em>ʿālāh</em>, to go up — here causative: to cause to come up). The verb is technically used of ascending from Sheol — the underworld conceptualized as below ground (cf. Ps 30:3; 86:13). Whether the woman actually raised Samuel or performed a deception the text does not explicitly adjudicate; the narrative presents what follows as a genuine exchange.</p>',
    "12": '<p><em>wattiṣʿaq bəqôl gādôl</em> — "she cried out with a loud voice." The sudden, surprised cry suggests the woman herself was startled — possibly indicating she expected her usual process of deception and received something unprecedented. Her immediate recognition of Saul (<em>lāmmāh rimmîtānî wəʾattāh šāʾûl</em>, "why did you deceive me? You are Saul!") occurs because seeing the genuine apparition revealed to her the identity of her client.</p>',
    "13": '<p><strong>ʾĕlōhîm ʿōlîm min hāʾāreṣ</strong> — "I see a divine figure rising up from the earth." <em>ʾĔlōhîm</em> (H430) is grammatically plural but takes a plural participle (<em>ʿōlîm</em>, "rising"). The term can mean "gods," "divine beings," "angels," or (rarely) "the God." Here the plural form is conventionally explained as a plural of majesty describing a single figure. The ambiguity is significant: the text does not identify this figure as definitively "Samuel\'s spirit" — the narrator uses the woman\'s description, leaving the nature of the apparition theologically open while making Samuel\'s identity the working assumption of the narrative.</p>',
    "14": '<p><em>mah tāʾrô</em> — "what does he look like?" (<em>tāʾrô</em> from <em>tōʾar</em>, H8389, form/appearance). The description — old man, wrapped in a robe (<em>məʿîl</em>) — triggers Saul\'s recognition: <em>wayyēdaʿ šāʾûl kî šəmûʾēl hûʾ</em> (Saul knew it was Samuel). The <em>məʿîl</em> is the priestly robe Samuel wore — the same garment whose edge Saul tore in 15:27. Recognition through a distinctive garment connects this scene to the covenant rupture of ch15.</p>',
    "15": '<p><em>lāmmāh hirgaztanî</em> — "why have you disturbed me?" (<em>rāgaz</em>, H7264, to quake/agitate). Samuel\'s first word is protest: the séance is a violation even of the dead\'s rest. <em>Bəṣar lî məʾōd</em> — "I am in desperate straits" — the same root <em>ṣārar</em> (to be cramped/distressed) used for extreme crisis. Saul then describes the triple silence of v6. Samuel\'s response to being called up is not sympathy but the reiteration of the verdict already pronounced.</p>',
    "16": '<p><em>sûr mēʿimmāḵ wayhî ʿārêḵā</em> — "the LORD has turned away (<em>sûr</em>, H5493) from you and become your adversary (<em>ṣar</em>, H6145)." <em>Sûr</em> is the departure-verb also used in 16:14 for the departure of the rûaḥ. The noun <em>ṣar</em> (foe/adversary) shares its root with <em>śāṭān</em> in function — the accuser who stands against. YHWH, who was the divine warrior fighting for Israel, is now positioned as Saul\'s enemy. Saul\'s question "why do you ask me?" (<em>lāmmāh tiš\'al bî</em>) receives the answer: there is no point asking the mediator when the one who would answer has become your opponent.</p>',
    "17": '<p><em>wayyaʿaś YHWH lô kaʾăšer dibbēr bəyādî</em> — "the LORD has done to you exactly what he said through me." The formula <em>kaʾăšer dibbēr bəyādî</em> (as he spoke by my hand) identifies Samuel as the instrument of YHWH\'s word — prophetic fulfillment terminology. The verb <em>qāraʿ</em> (torn) echoes 15:28; the same event is replayed in summary form: the kingdom was torn from Saul\'s hand and given to David (<em>rēʿeḵā</em>, "your neighbor," same word as 15:28).</p>',
    "18": '<p><em>lōʾ šāmaʿtā bəqôl YHWH</em> — "you did not obey the voice of YHWH." The <em>šāmaʿ</em> vocabulary from ch15 reappears as the explicit ground of the judgment. The failure was not listening-and-acting on Amalek (<em>lōʾ ʿāśîtā ḥărôn ʾappô bāʿămālēq</em>) — the fierce judgment not executed. The word <em>ḥărôn</em> (burning anger, H2740) marks the intensity of the divine command that was not carried out.</p>',
    "19": '<p><em>māḥār ʾattāh ûḇānêḵā ʿimmî</em> — "tomorrow you and your sons will be with me." The adverb <em>māḥār</em> (tomorrow) is a timed death sentence. The phrase <em>ʿimmî</em> (with me) means "in Sheol/in the realm of the dead" — Samuel is speaking from there. The double transfer announced: Israel and Saul into Philistine hands, and Saul-and-sons to Samuel in death. Both parts are fulfilled in ch31.</p>',
    "20": '<p><em>wayyimahēr wayyipôl mᵉlōʾ qômātô ʾarṣāh</em> — "Saul immediately fell full length on the ground." <em>Mᵉlōʾ qômātô</em> (literally "the fullness of his height") — Saul the tall man who stood head-and-shoulders above all Israel (9:2) is now measured out on the ground. The narrative detail is an acted emblem: his physical height had been his royal credential; now he lies that same height on the floor.</p>',
    "21": '<p>The woman shifts from medium to host. <em>wattarʾ ʾet šāʾûl kî nibhal məʾōd</em> — "she saw how shaken (<em>nāḇhal</em>, H926, to be dismayed/confused) he was." Her concern is practical — he needs strength to make the journey back. The moral texture is complex: the woman who performed the forbidden séance acts with genuine compassion; the narrative does not moralize.</p>',
    "22": '<p><em>šimʿā nāʾ gam ʾattāh bəqôl šipḥāteḵā</em> — "please listen to me" (<em>šāmaʿ bəqôl</em> — the obedience-of-hearing formula). The woman uses the vocabulary of covenantal hearing for a mundane request to eat. The phrase is ironic: the chapter turns on whether Saul listened to the right voices; now a necromancer uses the same idiom to urge physical sustenance.</p>',
    "23": '<p><em>waymāʾēn wayyōʾmer lōʾ ʾōḵal</em> — "he refused, saying I will not eat." <em>Māʾēn</em> (H3985, to refuse/decline) — the same root used in ch15 for covenant refusal themes. Saul\'s initial refusal gives way under sustained pressure (<em>wayyipṣar bô ʿăḇādāyw wəgam hāʾiššāh</em>). The eating of the meal is a final act of hospitality; after it, Saul goes to his death.</p>',
    "24": '<p>The woman\'s meal: fattened calf (<em>ʿēgel marbēq</em>), flour kneaded, unleavened bread (<em>maṣṣôt</em>). <em>Maṣṣôt</em> is the bread of the Passover and sacred meals; its use here is probably not symbolic but reflects the fastest bread to prepare (no waiting for leavening). The hospitality given to the doomed king at the hands of one who practices what Saul outlawed is one of the story\'s final ironies.</p>',
    "25": '<p><em>wayyāqumû wayyēlǝḵû ballaylāh hahûʾ</em> — "they rose and left that same night." The departure in darkness echoes the arrival in darkness (v8). Saul leaves Endor as he arrived — hidden, broken, and moving toward a death already announced. The chapter closes without commentary; the reader carries the weight of what was said in the darkness.</p>'
  },
  "29": {
    "1": '<p>Chapter 29 returns to the Philistine military context (interleaved with ch28\'s temporal setting). <em>ʾăpēq</em> (Aphek) is the marshaling point in the coastal plain; <em>ʿên ʾăšer beyizrəʿēl</em> (the spring at Jezreel) is the Israelite position. The geography establishes the forces converging for Gilboa.</p>',
    "2": '<p><em>waʾădōnê pəlištîm ʿōḇərîm lamēʾôt wəlāʾălāpîm</em> — "the Philistine lords passing in review by hundreds and thousands." The administrative review format mirrors Israelite mustering language (cf. 11:8; 15:4) — the Philistines have a structured military hierarchy. David and his men march at the rear with Achish — the most exposed position, furthest from the lords who will object.</p>',
    "3": '<p><em>ʾêleh hāʿiḇrîm māh lāhem</em> — "What are these Hebrews doing here?" <em>ʿIḇrî</em> (H5680, Hebrew) — a term used by outsiders for Israelites; it carries a social-class or ethnic-distinction connotation rather than being the covenant name. Achish\'s defense of David — <em>lōʾ māṣāʾtî bô məʾûmāh miyyôm nāpəlô ʿāday</em> (I have found nothing against him from the day he "fell" to me) — uses <em>nāpal ʾel</em> (fell to, defected to), the standard idiom for changing sides.</p>',
    "4": '<p><em>wəhāyāh lāmô ləśāṭān bamməlḥāmāh</em> — "he could turn against us in battle" (literally "he will become a śāṭān to us" — an adversary/accuser). The commanders use <em>śāṭān</em> (H7854, accuser/adversary) precisely: David as a potential fifth column. Their concern — <em>ûbammāh yitrāṣeh ʾel ʾădōnāyw</em> (how better to win back his lord\'s favor?) — correctly reads the political calculus: David would need to demonstrate loyalty to Saul by turning on the Philistines.</p>',
    "5": '<p>The commanders cite the battle-hymn of 18:7: <em>hikkāh šāʾûl bəʾălāpāyw wədāwid bərəḇāḇōtāyw</em> — "Saul has killed his thousands, David his ten thousands." The song that made Saul jealous (18:8-9) now surfaces as evidence that David is more dangerous than any ally. The song that nearly destroyed David in Saul\'s court now saves him from fighting against his own people.</p>',
    "6": '<p><em>ḥay YHWH kî yāšār ʾattāh</em> — "As the LORD lives, you have been trustworthy/upright" (<em>yāšār</em>, H3477, straight/upright). Achish swears by YHWH — a pagan king invoking Israel\'s God — to attest David\'s innocence. <em>ʾên māṣāʾtî bəḵā rāʿāh</em> — "I have found nothing wrong with you" — the forensic formula of acquittal. The double attestation (Achish at vv3, 6, 9) places a threefold hostile-witness declaration of David\'s innocence in the record. The irony: David is publicly exonerated by a Philistine lord at the very moment Saul is seeking illegal counsel to face the same battle.</p>',
    "7": '<p><em>wəšûḇ ûlēḵ bəšālôm</em> — "return and go in peace." The formula of peaceful dismissal releases David without dishonor. The narrative does not record David\'s inner response to being dismissed — whether relief or frustration is left to the reader, though the following chapter (Ziklag) shows the cost of the absence.</p>',
    "8": '<p>David\'s protest uses the formula of covenant service: <em>meh māṣāʾtā bəʿabdəḵā</em> — "what have you found against me?" The same language as Achish\'s own attestation (v6). Whether David genuinely wished to fight or was performing a necessary deception is left ambiguous; the text neither condemns nor commends the protestation.</p>',
    "9": '<p><em>ṭôḇ ʾattāh bəʿênay kəmalʾaḵ ʾĕlōhîm</em> — "you are as good in my sight as a messenger from God (<em>malʾaḵ ʾĕlōhîm</em>)." <em>Malʾaḵ ʾĕlōhîm</em> (H4397 + H430) — divine messenger/angel — is the highest praise Achish can offer: David is like a being from the divine realm in his trustworthiness. The phrase uses the same <em>ʾĕlōhîm</em> that appeared in 28:13 for the apparition at Endor; the juxtaposition — a spirit rising from the earth there, a trustworthy servant compared to a heavenly messenger here — frames the theological contrast between the two kings.</p>',
    "10": '<p><em>wəhiškamtem babbōqer</em> — "rise early in the morning." The command matches the narrative tempo: decisions in crisis must be executed quickly. David leaves without fighting either Israel or Philistia — his dilemma resolved by the very commanders who opposed him, with no moral compromise required of him.</p>',
    "11": '<p>The brief closing verse — David and his men return to Philistia, the Philistines march to Jezreel — leaves the two trajectories proceeding simultaneously. The reader knows both outcomes: David will face Ziklag (ch30), and the Philistines will face Saul at Gilboa (ch31). The narrative interleaving creates dramatic irony.</p>'
  },
  "30": {
    "1": '<p><em>bayyôm haššəlîšî</em> — "on the third day." The three-day delay during which Ziklag was burned matches the travel time from Aphek. <em>Amalêq</em> (Amalek) — the same enemy Saul failed to destroy in ch15. The destruction visited on David\'s base is precisely the enemy that Saul\'s disobedience left alive. The theological link between 15:7-9 and 30:1 is structural: Saul\'s incomplete ḥērem now strikes at YHWH\'s chosen king.</p>',
    "2": '<p><em>wəlōʾ hemîtû ʾîš</em> — "killing no one." The Amalekites\' restraint in not killing the captives makes total recovery possible; the verb <em>hemîtû</em> (Hiphil of <em>mût</em>, to kill) marks the exception. The captive-taking rather than slaughter anticipates the total recovery — nothing is permanently lost.</p>',
    "3": '<p>The discovery sequence: they came to the city, found it burned (<em>śərûpāh ʾēš</em>), wives and children gone. The verb <em>wəhinnēh</em> (and behold/look) introduces the shocking sight — a narrative particle that places the reader alongside the arriving soldiers at the moment of discovery.</p>',
    "4": '<p><em>wayyiśśəʾû ʾet qôlām wayyiḇkû ʿad ʾăšer lōʾ hāyāh lāhem kōaḥ liḇkôt</em> — "they wept aloud until they had no more strength to weep." The physical exhaustion of grief — weeping until strength is gone — is measured precisely. <em>Kōaḥ</em> (H3581, strength/power) spent on mourning; it will need to be restored (v6).</p>',
    "5": '<p>The specific naming of David\'s two wives — Ahinoam and Abigail — personalizes the crisis: this is not only his men\'s tragedy but his own. <em>Šəḇuyôt</em> (captives, from <em>šāḇāh</em>, H7617, to take captive) — the same root as the broader captivity of Israel in later periods; the individual event uses the vocabulary of national catastrophe.</p>',
    "6": '<p><strong>wayyiṯḥazzēq dāwid baYHWH ʾĕlōhāyw</strong> — "David strengthened himself in the LORD his God." The Hithpael of <em>ḥāzaq</em> (H2388) is uniquely reflexive: David is the agent of his own strengthening, drawing from YHWH the strength he needs. This is active faith — not passive reception but deliberate turning toward YHWH in the moment of crisis. The contrast with Saul (28:5: <em>wayyirāʾ</em>, was terrified; 28:7: seeking a medium) is the chapter\'s theological hinge. <em>ʾĕlōhāyw</em> — "his God" — the possessive marks covenantal relationship; YHWH is David\'s specifically, not only Israel\'s generically.</p>',
    "7": '<p><em>haggîšāh nāʾ lî ʾet hāʾēpôd</em> — "bring me the ephod." David immediately turns to the legitimate means of inquiry — the priestly ephod — rather than any illicit channel. Abiathar (son of Ahimelech, the priest Saul had murdered at Nob, ch22) is with David; the escaped priest enables the inquiry Saul could not access. The contrast with 28:6 (Urim closed to Saul) is pointed: the same sacred apparatus answers David but was silent to Saul.</p>',
    "8": '<p><strong>nāśōg tāśîg wəhaṣṣēl taṣṣîl</strong> — "you will certainly overtake them and certainly rescue the captives." Two infinitive absolute + imperfect constructions in sequence — the doubled certainty idiom in Hebrew. <em>Nāśag</em> (H5381, to overtake/reach) + <em>hiṣṣîl</em> (Hiphil of <em>nāṣal</em>, H5337, to deliver/rescue). The double absolute construction removes all uncertainty: YHWH\'s promise is unconditional and total. Compare 15:3 where the ḥērem command was also absolute — what Saul violated, David will fulfill in reverse through complete recovery.</p>',
    "9": '<p><em>naḥal habbesôr</em> — the brook Besor. The name is uncertain but may derive from a root meaning "fresh water." The brook divides those who go on (400) from those who remain (200). This geographical dividing point becomes the occasion for David\'s ruling in v24.</p>',
    "10": '<p><em>wayirdōp dāwid hûʾ wəʾarbaʿ mēʾôt ʾîš</em> — David goes with 400; 200 "were too exhausted (<em>pāgar</em>, H6296, to be faint/worn out) to cross the Besor." <em>Pāgar</em> denotes physical depletion — they were not cowardly but depleted. The distinction matters for David\'s ruling in v24.</p>',
    "11": '<p>The Egyptian slave found in the field functions as a providential discovery — an abandoned source of intelligence. <em>Wayyimṣəʾû ʾîš miṣrî baśśādeh</em> — "they found an Egyptian in the field" — the passive discovery (<em>māṣāʾ</em>, to find) rather than active pursuit. Food and water are immediately given before any questioning — basic hospitality before information extraction.</p>',
    "12": '<p><em>wayyittənû lô peleaḥ dəḇēlāh ûšətê ṣimmûqîm</em> — fig cake and raisin clusters — concentrated energy food for a man three days without sustenance. <em>Wattāšob rûḥô ʾēlāyw</em> — "his strength/spirit returned to him" (<em>rûaḥ</em>, H7307, spirit/breath). The restorative function of food and drink prepares the Egyptian to serve as guide.</p>',
    "13": '<p>The Egyptian\'s story: slave of an Amalekite, abandoned when ill three days ago. <em>Wayyaʿazbēnî ʾădōnî kî ḥālîtî</em> — "my master abandoned me when I fell sick." The contrast with David\'s treatment of his men (vv9-10) is implicit: David does not abandon the exhausted at Besor; the Amalekite abandoned a sick slave. The abandoned slave leads David to the raiders.</p>',
    "14": '<p>The Egyptian\'s geographical inventory of the raid: Negeb of the Cherethites, Negeb of Judah, Negeb of Caleb, then Ziklag burned. <em>Nəḡeḇ</em> (H5045, south/Negeb region) — the semi-arid zone south of Judah where David operated. The Cherethites are associated with the Philistine sphere; the raid covered both Philistine and Judahite territory, explaining why both David (Philistine subject) and Judah (Israelite territory) were hit.</p>',
    "15": '<p><em>wəhišbaʿ lî bēʾlōhîm ʾim timitēnî</em> — "swear to me by God that you won\'t kill me or hand me back to my master." The oath invokes <em>ʾĕlōhîm</em> — the Egyptian uses the generic divine name rather than YHWH; David swears by the God of Israel to an Egyptian. The exchange is entirely practical and mutually beneficial — no coercion on David\'s side.</p>',
    "16": '<p><em>pəšûṭîm ʿal pənê kol hāʾāreṣ ʾōḵəlîm wəšōṯîm wəḥōgĕgîm</em> — "spread out across the land, eating, drinking, and celebrating." The Amalekites are caught in post-victory celebration, which renders them militarily vulnerable. <em>Ḥōgĕgîm</em> (from <em>ḥāgag</em>, H2287, to celebrate a feast/dance) — pilgrimage-festival language applied to pagan revelry. The verb\'s sacred connotation in Israel makes its use here ironic.</p>',
    "17": '<p><em>wayyakkēm dāwid minnešep wəʿad hāʿereb limmāḥărātām</em> — "David struck them from twilight until the evening of the following day." The extended battle time — overnight into the next day — signals determined, total pursuit. <em>Lōʾ nimlaṭ mēhem ʾîš kî ʾim ʾarbaʿ mēʾôt ʾîš naʿar</em> — only 400 young men escaped on camels. The completeness of the defeat (with only the camel-mounted escape force surviving) contrasts with Saul\'s incomplete destruction of Amalek in ch15.</p>',
    "18": '<p><em>wayyaṣṣēl dāwid ʾēt kol ʾăšer lāqəḥû hāʾămālēqîm</em> — "David recovered everything the Amalekites had taken." The verb <em>yaṣṣēl</em> (Hiphil of <em>nāṣal</em>, same root as the promise in v8) — the promise and its fulfillment use identical vocabulary. <em>Wəʾēt šətê nāšāyw hiṣṣîl dāwid</em> — "including his two wives." The personal element of recovery is specified first before the general summary in v19.</p>',
    "19": '<p><em>wəlōʾ neʾdar lāhem minnaqṭōn wəʿad gādôl ûminbānîm ûḇānôt ûmišlāl</em> — "nothing was missing — young or old, sons or daughters, any plunder." The Hebrew uses <em>neʾdar</em> (Niphal of <em>ʿādar</em>, H5737, to be missing/lacking) — the negative of "lacking." Total recovery is expressed as the absence of any deficit. The comprehensive list reinforces the double absolute certainty of v8: YHWH\'s word proved exactly true.</p>',
    "20": '<p><em>wayyiqḥ dāwid ʾet kol haṣṣōʾn wəhabbāqār</em> — David also seizes the livestock beyond what was originally taken from Ziklag. The men acknowledge this as David\'s spoil (<em>šəlal dāwid zeh</em>) — he has gained more than he lost. The surplus of recovery over loss will govern the distribution dispute of vv22-25.</p>',
    "21": '<p><em>wayyēlek dāwid ʾel māʾtāyim hāʾănāšîm ʾăšer pāgərû</em> — "David returned to the two hundred men who had been too exhausted to follow." <em>Wayyišʾal lāhem ləšālôm</em> — "he greeted them warmly" (literally "asked them of peace"). The formal greeting of peace (<em>šālôm</em>) before any question of spoil-sharing is deliberate — David establishes relational regard before the economic dispute surfaces.</p>',
    "22": '<p><em>ʾanšê hārāʿ wəhaббəlîyāʿal</em> — "wicked and worthless men" (<em>rāʿ</em>, H7451, evil; <em>bəlîyāʿal</em>, H1100, worthlessness — literally "without profit/value"). <em>Bəlîyāʿal</em> is a term of contempt in the DtrH corpus (2:12, Eli\'s sons; Judg 19:22; 20:13). Their ruling — "they get only their wives and children" — reduces the exhausted men to non-participants. The justice issue is whether combat service alone qualifies for equal share.</p>',
    "23": '<p><em>lōʾ tǝʿăśû kēn ʾaḥay ʾēt ʾăšer nātan YHWH lānû</em> — "No, my brothers — that is not right with what the LORD has given us." David\'s counter grounds the ruling in theology, not equity: the spoil is YHWH\'s gift (<em>nātan</em>), not the warriors\' earnings. <em>Wayyišmor ʾōtānû</em> — "he kept us safe" — YHWH\'s protection of those who fought is the source of success, making human effort the secondary cause.</p>',
    "24": '<p><strong>kəḥēleq hayyōrēd bamməlḥāmāh ûkəḥēleq hayyōšēḇ ʿal hakkēlîm yəḥaddāw yəḥallēqû</strong> — "the share of the one who goes into battle is the same as the share of the one who stays with the supplies — they share equally." <em>Kēlîm</em> (H3627, vessels/equipment/supplies) — the "baggage" is military equipment, not personal belongings. The equal-share ruling is the practical expression of the theological principle: victory is YHWH\'s, the spoil is his gift, and the distribution reflects covenantal solidarity rather than proportional performance.</p>',
    "25": '<p><em>wayhî mēhayyôm hahûʾ wāmāʿlāh wayyəśîmēhā ləḥōq ûlemiṣpāṭ</em> — "from that day onward David made it a fixed rule (<em>ḥōq</em>, H2706) and ordinance (<em>miṣpāṭ</em>, H4941) for Israel." <em>Ḥōq</em> + <em>miṣpāṭ</em> is the paired legal terminology of covenant law (cf. Exod 15:25; Deut passim). David legislates at the moment of crisis — the ad hoc ruling becomes constitutional precedent.</p>',
    "26": '<p><em>wayyišlaḥ miššəlāl lə ziqnê yəhûdāh lərēʿēhû</em> — "he sent portions of the spoil to the elders of Judah — his friends." <em>Rēʿa</em> (H7453, neighbor/friend) — the same word used in 15:28 and 28:17 for David as Saul\'s "neighbor" who received the kingdom. Now David proactively builds covenant relationships through gift-giving. The list that follows (vv27-31) is a geographical network of Judahite loyalty-building.</p>',
    "27": '<p>The distribution towns — Bethel, Ramoth-negeb, Jattir — are in the Negeb of Judah, the region David traversed during his outlaw period. The gifts retroactively honor communities that provided cover and resources during David\'s years of flight.</p>',
    "28": '<p>Aroer, Siphmoth, Eshtemoa — further Judahite communities in the Negeb. The distribution is comprehensive rather than strategic — every community that sheltered David receives acknowledgment.</p>',
    "29": '<p>Racal, the Jerahmeelite towns, the Kenite towns — extending the gift-network to non-Israelite groups in the Negeb who maintained relationship with David. The Kenites (earlier spared from the Amalekite campaign at 15:6) reappear as allies.</p>',
    "30": '<p>Hormah, Bor-ashan, Athach — locations in the Negeb district; several unidentified with certainty. The list\'s completeness is the point: no community is overlooked, establishing David as a king who remembers those who helped him.</p>',
    "31": '<p><em>ûbəḥeḇrôn ûḇəkol hammaqōmôt ʾăšer hithallak šām dāwid hûʾ waʾănāšāyw</em> — "in Hebron — everywhere David and his men had wandered." <em>Heḇrôn</em> (Hebron) appears last and climactically: it will be the site of David\'s first anointing as king (2 Sam 2:1-4). The gift-network of ch30 anticipates the political base that will enable the transition of 2 Samuel.</p>'
  },
  "31": {
    "1": '<p><em>ûpəlištîm nilḥāmîm ʾel yiśrāʾēl wayyānusû ʾanšê yiśrāʾēl</em> — "the Philistines attacked Israel, and the Israelites fled." The verb <em>nûs</em> (H5127, to flee/escape) marks total military collapse; this is not a fighting retreat but a rout. <em>Wayyippəlû ḥălālîm bəhar haggILBŌʿA</em> — "falling slain on Mount Gilboa." The battle is narrated in five verses with the economy of catastrophe.</p>',
    "2": '<p><em>wayyadbiqû pəlištîm ʾet šāʾûl wəʾet bānāyw</em> — "the Philistines closed in hard on Saul and his sons." <em>Dāḇaq</em> (H1692, to cling/press hard against) — a pursuit verb implying the Philistines are faster and closing. Jonathan, Abinadab, and Malchishua are named — all three sons die. Jonathan\'s death is noted without elaboration here; 2 Sam 1:17-27 provides the full lament.</p>',
    "3": '<p><em>wayyiḵbad hamməlḥāmāh ʾel šāʾûl</em> — "the battle pressed hard against Saul" (<em>kāḇēd</em>, H3513, to be heavy — the same root as kāḇōd/honor; "weighty" battle). <em>Wayyimṣāʾuhû hammôrîm ʾănāšîm baqqešet wayyāḥel məʾōd méhammôrîm</em> — "the archers found their mark, and he was badly wounded" (<em>ḥûl</em>, H2342, to writhe/be in severe pain — often used of birth pangs). Saul is hit and incapacitated before making the decision of v4.</p>',
    "4": '<p><strong>ʾāḇāh / dāqar</strong> — "Draw your sword (<em>šəlōp ḥarbaḵā</em>) and run me through (<em>dāqar</em>, H1856, to stab/thrust through)." Saul\'s motive: <em>pen yāḇōʾû hāʿărēlîm hāʾēlleh ûdqārûnî wəhiṯʿallǝlû ḇî</em> — "lest these uncircumcised men come and abuse me." <em>Hithʿallel</em> (Hithpael of <em>ʿālal</em>, H5953, to act against/abuse/mock) — the fear is public dishonor rather than death itself. <em>Wayyimāʾēn</em> — "but his armor-bearer refused" (<em>māʾēn</em>, the same refusal-verb used in ch28:23 and ch15). Saul then falls on his own sword — <em>wayyiqaḥ šāʾûl ʾet haḥereb wayyippôl ʿāleyhā</em> — the self-destruction of the king is narrated in one clause.</p>',
    "5": '<p><em>wayyarʾ nōśēʾ kēlāyw kî mēt šāʾûl wayyippôl gam hûʾ ʿal ḥarəbô</em> — "when the armor-bearer saw that Saul was dead, he too fell on his own sword and died with him." The armor-bearer\'s death is briefly noted without commentary; his act is one of ancient honorable solidarity — the servant follows the master into death. The pairing of their deaths — master, then servant — frames Saul\'s end as comprehensively isolated from divine support.</p>',
    "6": '<p><em>wayyāmat šāʾûl ûšəlōšet bānāyw wənōśēʾ kēlāyw gam kol ʾănāšāyw bəyôm hahûʾ yaḥdāw</em> — "so Saul died, along with his three sons, his armor-bearer, and all his men — all on that same day (<em>yaḥdāw</em>)." <em>Yaḥdāw</em> (together/at once) provides the temporal closure: the Saulide dynasty ends in a single day, as Samuel prophesied (<em>māḥār</em> in 28:19). The word "together" (<em>yaḥdāw</em>) is the same word used for the equal sharing in 30:24 — but there it described communal solidarity; here it describes communal annihilation.</p>',
    "7": '<p><em>wayyaʿazbû ʾet hehārîm wayyānusû</em> — "they abandoned their cities and fled." The Israelite withdrawal from the Jezreel Valley and Transjordan follows the military collapse. <em>Wayyāḇōʾû pəlištîm wayyēšəḇû ḇāhēm</em> — "the Philistines came and settled in them." Philistine settlement of Israelite towns is the immediate geopolitical consequence; 2 Samuel opens in this situation.</p>',
    "8": '<p><em>wihyî mimmmāḥărāt</em> — "the next day." Philistine plundering of the dead was standard ancient military practice. <em>Wayyimṣəʾû ʾet šāʾûl wəʾet šəlōšat bānāyw nōpəlîm bəhar haggILBŌʿA</em> — "they found Saul and his three sons fallen on Mount Gilboa." The verb <em>māṣāʾ</em> (to find) — a discovery, not a pursuit. Saul is now an object to be found rather than a king who ruled.</p>',
    "9": '<p><strong>wayyəḇaśśərû</strong> — "to announce the victory" (<em>bāśar</em>, H1319, Piel, to bring good news / announce glad tidings). The root of <em>bəśōrāh</em> (good news/gospel) in its Hebrew form. The Philistines "evangelize" their gods (<em>ʿăṣabbêhem</em>) and people with Saul\'s death. The irony that the death of Israel\'s king is proclaimed as "good news" in pagan temples echoes the later NT inversion: the death of Israel\'s true King is proclaimed as good news to all nations. <em>Wayyāsîrû ʾet rōʾšô wəʾet kēlāyw</em> — head removed and armor stripped; the head would be displayed as a trophy (cf. David\'s display of Goliath\'s head, 17:54).</p>',
    "10": '<p><em>wayyāśîmû ʾet kēlāyw bêt ʿaštārôt</em> — "they placed his armor in the temple of Ashtaroth." Ashtaroth was the Canaanite goddess of war and fertility, associated with the Philistine pantheon. Dedicating captured armor to a deity was standard ancient Near Eastern victory practice — the spoil belongs to the god who gave the victory. Saul\'s armor ends as a votive offering; the man who was to be YHWH\'s covenant king becomes a trophy in a pagan sanctuary.</p>',
    "11": '<p>The people of Jabesh-gilead hear (<em>šāmᵉʿû</em>) what the Philistines did — the hearing that leads to action. Jabesh-gilead is the city Saul rescued in his first military act as king (ch11, from Nahash the Ammonite). The loyalty they display now is covenant-gratitude (<em>ḥesed</em> is the word 2 Sam 2:5 uses for their deed).</p>',
    "12": '<p><em>wayyāqumû kol ʾîš ḥayil wayyēlǝḵû kol hallaylāh</em> — "all their fighting men rose, traveled through the night." The night march mirrors Saul\'s night journey to Endor (28:8). But where Saul traveled in darkness to seek an illegal oracle, the men of Jabesh-gilead travel in darkness to perform a loyal burial. <em>Wayyiśrəpû ʾōtām šām</em> — "burned them there." Cremation was unusual in Israelite practice; this may reflect the advanced state of decomposition or Philistine mutilation, making burial of intact bodies impossible.</p>',
    "13": '<p><em>wayyiqəḥû ʾet ʿaṣmōtêhem wayyiqbərû taḥat hāʾēšel</em> — "they gathered the bones and buried them under the tamarisk tree (<em>ʾēšel</em>, H815)." <em>ʾĒšel</em> is the tamarisk — a tree associated with significant events (Abraham planted one at Beersheba, Gen 21:33; Saul sat under one at 22:6). The burial under a significant tree is a dignified interment for a fallen king. <em>Wayyāṣumû šiḇʿat yāmîm</em> — "they fasted for seven days." Seven-day mourning is the full period of intensive grief (cf. Job 2:13). The men of Jabesh-gilead honor Saul with the complete mourning rite — an act of covenant loyalty that will be explicitly commended by David in 2 Sam 2:5-6.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1samuel')
    merge_comm(existing, SAMUEL1)
    save_comm('mkt-original', '1samuel', existing)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1samuel.json'))
    all_ok = True
    for ch in [28, 29, 30, 31]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')
    print(f'Total chapters in file: {len(existing)}')

if __name__ == '__main__':
    main()
